+    regime_budgets.insert("attack".to_string(), budget * 3);
+    SchedulerConfig {
+        scheduler_id: "test-sched".to_string(),
+        base_budget_millionths: budget,
+        regime_budgets,
+        relevance_overrides: BTreeMap::new(),
+    }
