+        // Serde roundtrip on both entry and event
+        let diag_json = serde_json::to_string(&diag).unwrap();
+        let diag_rt: DiagnosticEntry = serde_json::from_str(&diag_json).unwrap();
+        assert_eq!(diag, diag_rt);
