+    let mut chart = CusumChart::new(3_000_000, 500_000).unwrap();
+    let mut signaled_round = 0u64;
+    for i in 0..20u64 {
+        let d = chart.observe(&obs(1_000_000, 800_000, i));
+        if d == StoppingDecision::Stop {
